import logging
from azure.storage.blob import BlockBlobService
from azure.common.exceptions import StorageException

def run(req):
    try:
        blob_path = req.get_json().get('blobPath')
        
        if not blob_path:
            return {"message": "Missing 'blobPath' query parameter"}, 400
        
        block_blob_service = BlockBlobService(account_name='your_account_name', account_key='your_account_key')

        container, blob = blob_path.split('/')

        try:
            data = block_blob_service.get_blob_to_text(container, blob)
            return {"data": data.content.decode('utf-8')}, 200
        except StorageException as e:
            logging.error(e)
            return {"message": "Failed to read the file"}, 500
    
    except Exception as e:
        logging.error(e)
        return {"message": "Internal Server Error"}, 500